mapper.update:
UPDATE 
    user_organization
SET 
    del_yn = CASE



                    WHEN user_id = #{userOrganization.userId}
                    AND organization_id = #{userOrganization.organizationId}
                    THEN #{userOrganization.delYn}


                    WHEN user_id = #{userOrganization.userId}
                    AND organization_id = #{userOrganization.organizationId}
                    THEN del_yn



        ELSE del_yn
    END,
    chg_id = CASE 



                    WHEN user_id = #{userOrganization.userId}
                    AND organization_id = #{userOrganization.organizationId}
                    THEN #{userOrganization.chgId}


                    WHEN user_id = #{userOrganization.userId}
                    AND organization_id = #{userOrganization.organizationId}
                    THEN chg_id



        ELSE chg_id
    END,
    chg_dt = CASE 



                    WHEN user_id = #{userOrganization.userId}
                    AND organization_id = #{userOrganization.organizationId}
                    THEN COALESCE(#{userOrganization.chgDt}, NOW())


                    WHEN user_id = #{userOrganization.userId}
                    AND organization_id = #{userOrganization.organizationId}
                    THEN chg_dt



        ELSE chg_dt
    END,
    del_id = 



                    WHEN user_id = #{userOrganization.userId} AND organization_id = #{userOrganization.organizationId} THEN NULL::uuid


                    WHEN user_id = #{userOrganization.userId} AND organization_id = #{userOrganization.organizationId} THEN #{userOrganization.delId}


                    WHEN user_id = #{userOrganization.userId} AND organization_id = #{userOrganization.organizationId} THEN del_id


        ,
    del_dt = 



                    WHEN user_id = #{userOrganization.userId} AND organization_id = #{userOrganization.organizationId} THEN NULL::timestamp


                    WHEN user_id = #{userOrganization.userId} AND organization_id = #{userOrganization.organizationId} THEN #{userOrganization.delDt}


                    WHEN user_id = #{userOrganization.userId} AND organization_id = #{userOrganization.organizationId} THEN del_dt



WHERE (user_id, organization_id) IN (

        (#{userOrganization.userId},
         #{userOrganization.organizationId})

)

