mapper.select:
SELECT uo.user_id, uo.organization_id, u.user_name, o.organization_name, u.email, uo.reg_id, uo.reg_dt, uo.chg_id, uo.chg_dt, uo.del_id, uo.del_dt, uo.del_yn FROM user_organization uo INNER JOIN user u ON uo.user_id = u.user_id INNER JOIN organization o ON uo.organization_id = o.organization_id
AND uo.user_id IN
#{userId}
AND uo.organization_id IN
#{organizationId}
AND u.user_name ILIKE '%' || #{filter.userName} || '%'
AND o.organization_name ILIKE '%' || #{filter.organizationName} || '%'
AND uo.del_yn = #{filter.delYn}
